import{_ as a,p as e,q as i,a1 as h}from"./framework-caba6eb2.js";const r={},t=h('<h1 id="同步" tabindex="-1"><a class="header-anchor" href="#同步" aria-hidden="true">#</a> 同步</h1><p>有了同步功能，你可以：</p><ul><li>在多设备登录同一个图书馆账号，且不发生冲突。</li><li>等等</li></ul><p>同步功能在适时将会开放。也可以在我的-看板查看最新动态。</p><h2 id="ham账号" tabindex="-1"><a class="header-anchor" href="#ham账号" aria-hidden="true">#</a> Ham账号</h2><p>你必须登录Ham账号才能使用同步功能。Ham支持的登录方式有QQ登录、微信登录、Github登录和Apple登录（iOS）。</p><p>登录账号后，你可以在个人信息页查看已登录的设备，或查看已绑定的社交账号。当然你也可以移除某些已经登录的设备，或移除某些绑定的社交账号。</p><h2 id="注销账号" tabindex="-1"><a class="header-anchor" href="#注销账号" aria-hidden="true">#</a> 注销账号</h2><p>根据《中华人民共和国个人信息保护法》规定，你随时可以在设置中注销自己的账号。注销后，你将无法使用同步功能，并且你的所有的个人信息、设备信息、登录状态、社交账号等将在Ham服务器抹掉。所以在您准备注销账号时，请三思而后行。</p><h2 id="必要的权限" tabindex="-1"><a class="header-anchor" href="#必要的权限" aria-hidden="true">#</a> 必要的权限</h2><ul><li>通知 - 用于同步状态</li><li>网络 - 用于连接Ham服务器，作为中转推送到其它设备</li><li>第三方登录 - 用于鉴别身份</li></ul>',11),l=[t];function d(n,c){return e(),i("div",null,l)}const o=a(r,[["render",d],["__file","sync.html.vue"]]);export{o as default};
